@startuml
'option handwritten true

skinparam classAttributeIconSize 0

abstract class Container {
  +__contains__(item)
}

abstract class Iterable {
  +__iter__()
}

abstract class Sized {
  +__len__(item)
}

abstract class Collection

abstract class Mapping {
  +__getitem__(key)
  +keys()
  +items()
  +values()
  +get(key, default)
}

abstract class MutableMapping {
  +__setitem__(key, value)
  +__delitem__(key)
}

class dict

Collection -up-|> Container
Collection -up-|> Iterable
Collection -up-|> Sized

Mapping -up-|> Collection
MutableMapping -up-|> Mapping
dict -up-|> MutableMapping

